#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
const int N=1010;
ll n,m,a,b,d,s;
queue<ll> q;
ll num,u[N],v[N],nx[N],h[N];
ll fa[N],f[N],an[N];
char c,A,B;
bool o1,o2,p;
signed main(void)
{
    n=read();
    m=read();
    FOR(iii,1,m)
    {
        char A,t,B;
        cin>>A>>t>>B;
        a=A-'A'+1;
        b=B-'A'+1;
        if(p)continue;
        fa[b]++;
        num++;
        u[num]=a;
        v[num]=b;
        nx[num]=h[a];
        h[a]=num;
        FOR(i,1,n)f[i]=fa[i];
        o1=1;
        o2=1;
        s=0;
        FOR(i,1,n)
        {
            if(f[i]==0)
            {
                if(o2)o2=0;
                else o1=0;
                q.push(i);
            }
        }
        wh(!q.empty())
        {
            d=q.front();
            q.pop();
            an[++s]=d;
            o2=1;
            for(int i=h[d];i>0;i=nx[i])
            {
                f[v[i]]--;
                if(f[v[i]]==0)
                {
                    if(o2)o2=0;
                    else o1=0;
                    q.push(v[i]);
                }
            }
        }
        FOR(i,1,n)
        {
            if(f[i]!=0)
            {
                printf("Inconsistency found after %lld relations.",iii);
                p=1;
                break;
            }
        }
        if(p)continue;
        if(s==n&&o1)
        {
            printf("Sorted sequence determined after %lld relations: ",iii);
            FOR(i,1,n)
            {
                printf("%c",'A'+an[i]-1);
            }
            printf(".");
            p=1;
        }
    }
    if(!p)printf("Sorted sequence cannot be determined.");
    return 0;
}
